section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-test-data-catalog.json",
  "type": "object",
  "title": "QA Test Data Catalog",
  "required": [
    "catalog_id",
    "fixtures",
    "blocked_patterns",
    "stale_threshold_days",
    "last_reviewed"
  ],
  "additionalProperties": false,
  "properties": {
    "catalog_id": {
      "type": "string",
      "minLength": 1,
      "description": "Catalog identifier."
    },
    "fixtures": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {id, owner_service, refresh \u2208 [test,function,module,session,persistent], contains_pii, factory_path, consumers}."
    },
    "blocked_patterns": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Regex patterns of forbidden direct ORM creates."
    },
    "stale_threshold_days": {
      "type": "integer",
      "description": "Days of zero-consumer triggering removal flag; \u226490."
    },
    "last_reviewed": {
      "type": "string",
      "minLength": 1,
      "description": "ISO date."
    }
  }
}
